import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

function quoteResult(items: Array<Record<string, unknown>>, yearsWithMHPCO = 0) {
  const result = processScenario({
    customer: { yearsWithMHPCO },
    steps: [{ op: "quote" as const, items }],
  }) as { results: Array<{ premium: number }> };
  return result.results[0].premium;
}

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("should return 5G premium for empty item list (processing fee only)", () => {
      expect(quoteResult([])).toBe(5);
    });
    it("should return premium for a single sword (100 base + 10 first ins + 5 fee = 115G)", () => {
      expect(quoteResult([{ type: "sword", material: "steel", enchantment: 0, cursed: false }])).toBe(115);
    });
    it("should return premium for a single amulet (60 base + 6 first ins + 5 fee = 71G)", () => {
      expect(quoteResult([{ type: "amulet", material: "silver", enchantment: 0, cursed: false }])).toBe(71);
    });
    it("should return premium for a single staff (80 base + 8 first ins + 5 fee = 93G)", () => {
      expect(quoteResult([{ type: "staff", material: "oak", enchantment: 0, cursed: false }])).toBe(93);
    });
    it("should return premium for a single potion (40 base + 4 first ins + 5 fee = 49G)", () => {
      expect(quoteResult([{ type: "potion", material: "glass", enchantment: 0, cursed: false }])).toBe(49);
    });
  });

  describe("Quote - components", () => {
    it("should charge 25G per component (2 runes = 50 + 5 = 55G)", () => {
      expect(quoteResult([
        { type: "rune" },
        { type: "rune" },
      ])).toBe(60);
    });
    it("should apply block discount for exactly 3 alike components (3 runes block 60 + 6 first ins + 5 fee = 71G)", () => {
      expect(quoteResult([
        { type: "rune" },
        { type: "rune" },
        { type: "rune" },
      ])).toBe(71);
    });
    it("should not apply block for 4 alike components (4 runes = 100 + 10 first ins + 5 fee = 115G)", () => {
      expect(quoteResult([
        { type: "rune" },
        { type: "rune" },
        { type: "rune" },
        { type: "rune" },
      ])).toBe(115);
    });
    it("should not apply block for 3 different components (2r+1m = 75 + 7.5 first ins + 5 fee = 88G)", () => {
      expect(quoteResult([
        { type: "rune" },
        { type: "rune" },
        { type: "moonstone" },
      ])).toBe(88);
    });
    it("should apply two separate blocks for 3 runes + 3 moonstones (120 + 12 first ins + 5 fee = 137G)", () => {
      expect(quoteResult([
        { type: "rune" },
        { type: "rune" },
        { type: "rune" },
        { type: "moonstone" },
        { type: "moonstone" },
        { type: "moonstone" },
      ])).toBe(137);
    });
  });

  describe("Quote - item-specific modifiers", () => {
    it("should add 50% cursed surcharge to the cursed item's base premium", () => {
      expect(quoteResult([
        { type: "sword", material: "steel", enchantment: 0, cursed: true },
      ])).toBe(165);
    });
    it("should add 30% high-enchantment surcharge for enchantment >= 5", () => {
      expect(quoteResult([
        { type: "sword", material: "steel", enchantment: 5, cursed: false },
      ])).toBe(145);
    });
    it("should apply both cursed and high-enchantment surcharges to the same item", () => {
      expect(quoteResult([
        { type: "sword", material: "steel", enchantment: 5, cursed: true },
      ])).toBe(195);
    });
    it("should not apply high-enchantment surcharge for enchantment 4", () => {
      expect(quoteResult([
        { type: "sword", material: "steel", enchantment: 4, cursed: false },
      ])).toBe(115);
    });
  });

  describe("Quote - policy-wide modifiers", () => {
    it("should add 10% first-insurance surcharge (always applies per quote)", () => {
      // sword base 100, first insurance 10% of 100 = 10, total 110 + 5 fee = 115
      expect(quoteResult([
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
      ])).toBe(115);
    });
    it("should apply 20% loyalty discount for customer with >= 2 years", () => {
      // sword base 100, first ins +10, loyalty -20 = 90 + 5 fee = 95
      expect(quoteResult([
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
      ], 2)).toBe(95);
    });
    it("should apply 15% follow-up discount on second and subsequent quotes", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          { op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
          { op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
        ],
      }) as { results: Array<{ premium: number }> };
      // first quote: 100 + 10 first ins + 5 fee = 115
      expect(result.results[0].premium).toBe(115);
      // second quote: 100 + 10 first ins - 15 follow-up + 5 fee = 100
      expect(result.results[1].premium).toBe(100);
    });
    it.todo("should apply item-specific modifiers per item and policy-wide modifiers on the sum");
  });

  describe("Quote - processing fee and rounding", () => {
    it.todo("should add 5G processing fee after all modifiers");
    it.todo("should round premium up (in MHPCO's favor)");
  });

  describe("Quote - integration", () => {
    it.todo("should compute 165G for newcomer with cursed sword");
    it.todo("should compute 160G for long-standing customer's second contract with cursed high-ench sword");
  });

  describe("Claim - basic", () => {
    it.todo("should apply 100G deductible per damaged item");
    it.todo("should reimburse at 50% for enchantment >= 8 then apply deductible");
    it.todo("should fully reimburse dragon material then apply deductible");
    it.todo("should apply 50% when both enchantment >= 8 and dragon material");
    it.todo("should handle multiple damaged items each with own deductible");
  });

  describe("Claim - cap", () => {
    it.todo("should cap total payout at 2x insurance sum");
    it.todo("should track remaining cap across multiple claims on same policy");
    it.todo("should reduce payout to remaining cap when cap is nearly exhausted");
  });

  describe("Claim - components", () => {
    it.todo("should apply deductible to component damage (rune damage 200G = payout 100G)");
  });

  describe("Error handling", () => {
    it.todo("should reject unknown item type in quote");
    it.todo("should reject claim referencing item not in policy");
    it.todo("should reject negative damage amount");
    it.todo("should reject more damages of a type than policy covers");
  });

  describe("CLI integration", () => {
    it.todo("should process a full scenario with quote and claim via processScenario");
  });
});

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
}

export function processScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      let policyBasePremium = 0;
      let itemSurcharges = 0;
      const componentCounts: Record<string, number> = {};
      for (const item of step.items) {
        if (COMPONENT_TYPES.has(item.type)) {
          componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
        } else {
          const itemBase = BASE_PREMIUMS[item.type] ?? 0;
          policyBasePremium += itemBase;
          if (item.cursed) {
            itemSurcharges += itemBase * 0.5;
          }
          if ((item.enchantment ?? 0) >= 5) {
            itemSurcharges += itemBase * 0.3;
          }
        }
      }
      for (const [, count] of Object.entries(componentCounts)) {
        if (count === 3) {
          policyBasePremium += COMPONENT_BLOCK_PREMIUM;
        } else {
          policyBasePremium += count * COMPONENT_PREMIUM;
        }
      }
      const firstInsurance = policyBasePremium * 0.1;
      const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
      const premium = policyBasePremium + itemSurcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
      return { premium: Math.ceil(premium) };
    }
    return {};
  });
  return { results };
}

